+    timerRef.current = setTimeout(() => {
+      setCopied(false);
+      timerRef.current = null;
+    }, 2000);
+  }, [prompt]);
+
+  // Very simple client-side syntax highlighting for structural keywords
+  const highlightPrompt = (text: string) => {
