+            {whyItWorks && (
+              <div className="flex items-start gap-2.5">
+                <Lightbulb className="h-4 w-4 text-amber-400 shrink-0 mt-0.5" />
+                <p className="text-xs sm:text-sm text-white/70 leading-relaxed">{whyItWorks}</p>
+              </div>
+            )}
+          </motion.div>
